import { useState } from "react"
import API from "../api/axios"

export default function Chatbot() {
  const [msg,setMsg]=useState("")
  const [chat,setChat]=useState([])

  const send=async()=>{
    const res=await API.post("/ai-assistant/chat",{message:msg,conversation_history:chat})
    setChat([...chat,{user:msg,bot:res.data.response}])
    setMsg("")
  }

  return (
    <div className="fixed bottom-4 right-4 bg-white p-4 rounded-xl shadow w-72">
      <h3 className="font-bold">Assistant</h3>
      <div className="h-40 overflow-y-auto text-sm">
        {chat.map((c,i)=>(
          <div key={i}>
            <p className="text-gray-500">{c.user}</p>
            <p>{c.bot}</p>
          </div>
        ))}
      </div>
      <input className="border w-full mt-2 p-1" value={msg} onChange={e=>setMsg(e.target.value)} />
      <button className="bg-red-600 text-white w-full mt-2 p-1" onClick={send}>Send</button>
    </div>
  )
}
